const CATEGORY_WEIGHT: Record<string, number> = {
  "t-shirt": 400,
  "shirt": 400,
  "denims": 950,
  "jacket": 950,
  "hoodie": 950,
  "sweatshirt": 950,
  "lower": 600,
};

const NAME_WEIGHT_EXCEPTIONS: Record<string, number> = {
  "parth tshirt": 600,
};

function getProductWeight(
  category: string,
  name: string,
): { weight: number | null; unknownCategory: string | null } {
  const nameLower = name.toLowerCase().trim();
  const categoryLower = category.toLowerCase().trim();

  // Check name-level exceptions first
  if (nameLower in NAME_WEIGHT_EXCEPTIONS) {
    return { weight: NAME_WEIGHT_EXCEPTIONS[nameLower], unknownCategory: null };
  }

  // Match category
  for (const [cat, weight] of Object.entries(CATEGORY_WEIGHT)) {
    if (categoryLower.includes(cat)) {
      return { weight, unknownCategory: null };
    }
  }

  return { weight: null, unknownCategory: category || name };
}

