export const calcShipmentWeights = onRequest(
  { cors: true, timeoutSeconds: 540, memory: "2GiB" },
  async (req, res) => {
    const businessId = (req.query.businessId as string) || req.body?.businessId;
    if (!businessId) {
      res.status(400).json({ error: "businessId is required" });
      return;
    }

    // ── 1. Fetch orders by AWB in chunks of 30 ────────────────────────────
    const CHUNK_SIZE = 15;
    // awb → order data
    const orderByAwb = new Map<string, DocumentData>();

    const baseQuery = db.collection("accounts").doc(STORE_ID).collection("orders");

    for (let i = 0; i < UNIQUE_AWBS.length; i += CHUNK_SIZE) {
      const chunk = UNIQUE_AWBS.slice(i, i + CHUNK_SIZE);
      const snap = await baseQuery.where(
        Filter.or(
          Filter.where("awb", "in", chunk),
          Filter.where("awb_reverse", "in", chunk)
        )
      ).get();
      for (const doc of snap.docs) {
        const data = doc.data();

        if (data.awb) {
          orderByAwb.set(String(data.awb), data);
        }

        if (data.awb_reverse) {
          orderByAwb.set(String(data.awb_reverse), data);
        }
      }
    }

    // ── 2. Collect all unique variantIds across all orders ─────────────────
    // variantId → storeProductId (productId in accounts/{storeId}/products)
    const variantToProductId = new Map<string, string>();

    for (const order of orderByAwb.values()) {
      for (const item of order?.raw?.line_items ?? []) {
        const variantId = String(item.variant_id ?? "");
        const productId = String(item.product_id ?? "");
        if (variantId && productId) {
          variantToProductId.set(variantId, productId);
        }
      }
    }

    // ── 3. Fetch store product docs to resolve variant → business SKU ──────
    const uniqueProductIds = Array.from(new Set(variantToProductId.values()));

    const storeProductDocs = await Promise.all(
      uniqueProductIds.map((pid) =>
        db.doc(`accounts/${STORE_ID}/products/${pid}`).get()
      )
    );

    // variantId (string) → businessProductSku
    const variantToBusinessSku = new Map<string, string>();

    for (const doc of storeProductDocs) {
      if (!doc.exists) continue;
      const data = doc.data()!;
      const variantMappings: Record<string, any> =
        data.variantMappingDetails ?? data.variantMappings ?? {};
      for (const [variantId, mapping] of Object.entries(variantMappings)) {
        const sku =
          typeof mapping === "object"
            ? mapping.businessProductSku
            : mapping;
        if (sku) variantToBusinessSku.set(String(variantId), String(sku));
      }
    }

    // ── 4. Fetch all business product docs ────────────────────────────────
    const uniqueSkus = Array.from(new Set(variantToBusinessSku.values()));

    const businessProductDocs = await Promise.all(
      uniqueSkus.map((sku) =>
        db.doc(`users/${businessId}/products/${sku}`).get()
      )
    );

    // sku → { category, name }
    const skuToProduct = new Map<string, { category: string; name: string }>();
    for (const doc of businessProductDocs) {
      if (!doc.exists) continue;
      const data = doc.data()!;
      skuToProduct.set(doc.id, {
        category: String(data.category ?? ""),
        name: String(data.name ?? ""),
      });
    }

    // ── 5. Compute weights per order ──────────────────────────────────────
    const results: Array<{
      awb: string;
      orderName: string;
      totalWeightKg: number;
      items: Array<{ sku: string; category: string; name: string; qty: number; unitWeightGm: number }>;
    }> = [];

    const errors: Array<{
      awb: string;
      orderName: string;
      reason: string;
      unknownCategories?: string[];
    }> = [];

    const notFound: string[] = UNIQUE_AWBS.filter((awb) => !orderByAwb.has(awb));

    for (const awb of UNIQUE_AWBS) {
      const order = orderByAwb.get(awb);
      if (!order) continue; // reported in notFound

      const orderName = String(order.name ?? awb);
      const lineItems: any[] = order?.raw?.line_items ?? [];

      if (lineItems.length === 0) {
        errors.push({ awb, orderName, reason: "No line items found" });
        continue;
      }

      let totalGrams = 0;
      const itemResults: typeof results[0]["items"] = [];
      const unknownCategories: string[] = [];
      let hadError = false;

      for (const item of lineItems) {
        const variantId = String(item.variant_id ?? "");
        const qty = Number(item.quantity ?? 1);

        const businessSku = variantToBusinessSku.get(variantId);
        if (!businessSku) {
          unknownCategories.push(`variantId:${variantId} (no mapping)`);
          hadError = true;
          continue;
        }

        const product = skuToProduct.get(businessSku);
        if (!product) {
          unknownCategories.push(`sku:${businessSku} (product not found)`);
          hadError = true;
          continue;
        }

        const { weight, unknownCategory } = getProductWeight(product.category, product.name);

        if (weight === null) {
          unknownCategories.push(`sku:${businessSku} category:"${unknownCategory}"`);
          hadError = true;
          continue;
        }

        totalGrams += weight * qty;
        itemResults.push({
          sku: businessSku,
          category: product.category,
          name: product.name,
          qty,
          unitWeightGm: weight,
        });
      }

      if (hadError) {
        errors.push({
          awb,
          orderName,
          reason: "Could not resolve weight for some items",
          unknownCategories,
        });
        // Still include partial weight if any items resolved
        if (itemResults.length > 0) {
          results.push({
            awb,
            orderName,
            totalWeightKg: Math.ceil((totalGrams / 1000) * 2) / 2,
            items: itemResults,
          });
        }
        continue;
      }

      results.push({
        awb,
        orderName,
        totalWeightKg: Math.ceil((totalGrams / 1000) * 2) / 2,
        items: itemResults,
      });
    }

    res.status(200).json({
      summary: {
        totalAwbs: UNIQUE_AWBS.length,
        resolved: results.length,
        errors: errors.length,
        notFound: notFound.length,
      },
      results: results.sort((a, b) => a.awb.localeCompare(b.awb)),
      errors,
      notFound,
    });
  }
);